from fastapi import APIRouter, HTTPException
from pydantic import BaseModel
import uuid

router = APIRouter(prefix="/v1/runs", tags=["runs"])

class CreateRun(BaseModel):
    prompt: str
    tools: list[str] = []
    session_id: str | None = None

class RunResponse(BaseModel):
    id: str
    status: str  # queued | running | completed | failed

@router.post("", response_model=RunResponse, status_code=201)
async def create_run(body: CreateRun) -> RunResponse:
    run_id = str(uuid.uuid4())
    run = await service.start_run(run_id, body.prompt, tools=body.tools, session_id=body.session_id)
    return RunResponse(id=run.id, status=run.status)

@router.get("/{run_id}", response_model=RunResponse)
async def get_run(run_id: str) -> RunResponse:
    run = await service.get_run(run_id)
    if run is None:
        raise HTTPException(404, detail="run not found")
    return RunResponse(id=run.id, status=run.status)

from fastapi import APIRouter, HTTPException
from pydantic import BaseModel
import uuid

from services.store import Store

router = APIRouter(prefix="/sessions", tags=["sessions"])

class CreateSession(BaseModel):
    persona: str = "helpful assistant"

class SessionResponse(BaseModel):
    id: str
    persona: str

@router.post("", response_model=SessionResponse, status_code=201)
async def create_session(body: CreateSession) -> SessionResponse:
    session_id = str(uuid.uuid4())
    await Store.save_session(session_id, {"persona": body.persona, "history": []})
    return SessionResponse(id=session_id, persona=body.persona)

@router.get("/{session_id}", response_model=SessionResponse)
async def get_session(session_id: str) -> SessionResponse:
    session = await Store.get_session(session_id)
    if session is None:
        raise HTTPException(404, detail="session not found")
    return SessionResponse(id=session_id, persona=session["persona"])

@router.delete("/{session_id}", status_code=204)
async def delete_session(session_id: str) -> None:
    deleted = await Store.delete_session(session_id)
    if not deleted:
        raise HTTPException(404, detail="session not found")

from pydantic import BaseModel, Field
from typing import Literal

class ErrorBody(BaseModel):
    code: str
    message: str
    details: dict | None = None
    # example: {"code": "tool_not_found", "message": "Unknown tool: search"}

class RunStatus(BaseModel):
    id: str
    status: Literal["queued", "running", "completed", "failed"]
    created_at: str
    completed_at: str | None = None
    output: str | None = None  # populated when status == completed
    error: str | None = None   # populated when status == failed

class ToolSchema(BaseModel):
    name: str
    description: str
    parameters: dict = Field(description="JSON Schema for tool input")

    model_config = {"json_schema_extra": {
        "example": {
            "name": "search_web",
            "description": "Search the web and return top results",
            "parameters": {
                "type": "object",
                "properties": {"query": {"type": "string"}},
                "required": ["query"]
            }
        }
    }}
